async def main():
    from sqlalchemy.ext.asyncio import create_async_engine
    from sqlalchemy import text
    eng = create_async_engine(os.environ['DATABASE_URL'])
    updated = 0
    skipped = 0
    async with eng.begin() as conn:
        await conn.execute(text(f"SET LOCAL app.tenant_id = '{SHOP_TID}'"))
        for name_fa, desc in UPDATES:
            safe_desc = desc.replace("'", "''")
            safe_name = name_fa.replace("'", "''")
            r = await conn.execute(text(
                f"UPDATE shop_products "
                f"SET description = '{safe_desc}', updated_at = NOW() "
                f"WHERE tenant_id = '{SHOP_TID}' "
                f"AND (name_fa ILIKE '%{safe_name}%' OR name ILIKE '%{safe_name}%')"
            ))
            if r.rowcount > 0:
                updated += 1
                print(f"OK: {name_fa}")
            else:
                skipped += 1
                print(f"SKIP (not found): {name_fa}")
    print(f"\nDONE: {updated} updated, {skipped} not found")

asyncio.run(main(), loop_factory=asyncio.SelectorEventLoop)
